def perceive(data):
    out = {}
    for line in str(data).splitlines():
        if ':' not in line:
            continue
        k, v = line.split(':', 1)
        k = k.strip().lower(); v = v.strip()
        if k in ('custodians', 'items'):
            n = int(v) if v.lstrip('-').isdigit() else 0
            out['custodians' if k == 'custodians' else 'preserved_items'] = max(0, n)
        elif k == 'status' and v.lower() in ('active', 'released', 'none'):
            out['status'] = v.lower()
    return out
